SELECT p.payroll_id, p.employee_id, e.name AS employee_name, p.pay_month, p.base_pay, p.allowance, p.bonus, p.deduction, p.social_insurance, p.tax, p.net_pay, p.pay_date, p.created_at FROM payroll_info p LEFT JOIN employee_info e ON p.employee_id = e.employee_id
AND p.employee_id = #{employeeId}
AND e.name LIKE CONCAT('%', #{employeeName}, '%')
AND p.pay_month = #{payMonth}
AND p.pay_month >= #{startMonth}
AND p.pay_month <= #{endMonth}
ORDER BY p.pay_month DESC, p.created_at DESC LIMIT #{pageSize} OFFSET #{pageNum}

SELECT COUNT(*)
FROM payroll_info p
LEFT JOIN employee_info e ON p.employee_id = e.employee_id


        AND p.employee_id = #{employeeId}


        AND e.name LIKE CONCAT('%', #{employeeName}, '%')


        AND p.pay_month = #{payMonth}


        AND p.pay_month >= #{startMonth}


        AND p.pay_month <= #{endMonth}

SELECT 
    payroll_id, employee_id, pay_month, base_pay, allowance, bonus,
    deduction, social_insurance, tax, net_pay, pay_date, created_at
FROM payroll_info
WHERE employee_id = #{employeeId}
  AND pay_month = #{payMonth}
